Sync Output Update Category Priority Reason Guide score ≥ 3 Help Files High Guide needs → help docs Guide score ≥ 3 Changelog High New feature → changelog entry Refcard score ≥ 3 Help Files Medium Quick ref → help YAML Demo score ≥ 3 GIF Regeneration High Demo needed → regenerate GIFs Mermaid score ≥ 3 (N/A - manual) Low Diagrams are tutorial content Stale docs detected Broken Links Medium Stale → likely broken refs Stale docs detected Version References Low Old docs → old versions New commands found Help Files High New command → create help New modules found Tutorials Medium New module → tutorial <p>Implementation:</p> <pre><code>def map_classification_to_categories(result: SyncResult) -&gt; List[Tuple[str, int]]:
    """Map sync scores to update categories with priority"""
    categories = []

    if result.classifications.get("guide", 0) &gt;= 3:
        categories.append(("help", 10))  # High priority
        categories.append(("changelog", 9))

    if result.classifications.get("demo", 0) &gt;= 3:
        categories.append(("gifs", 8))

    if result.classifications.get("refcard", 0) &gt;= 3:
        categories.append(("help", 7))

    if len(result.stale_docs) &gt; 0:
        categories.append(("links", 6))
        categories.append(("version", 5))

    if len(result.changes_detected) &gt; 0:
        # Analyze change types
        for change in result.changes_detected:
            if change.type == "new_command":
                categories.append(("help", 9))
            elif change.type == "new_module":
                categories.append(("tutorials", 7))

    # Remove duplicates, sort by priority
    unique = dict(categories)  # Keeps highest priority per category
    return sorted(unique.items(), key=lambda x: x[1], reverse=True)
